import {createGlobalStyle} from "styled-components";

import wood from '../wood.jpg';
import leather from '../leather.jpg';

const GlobalStyles = createGlobalStyle`
	* {
		margin: 0;
		padding: 0;
		box-sizing: border-box;
	}

	html {
		background: #7b0046;
	}
	
	body {
		background: url('${wood}') fixed;
		font-family: Nunito, sans-serif;
	}
	body:after {
		content: '';
		display: block;
		position: fixed;
		top: 2rem;
		left: 2rem;
		right: 2rem;
		bottom: 2rem;
		background: url('${leather}');
		border-radius: 10px;
		box-shadow: 0px 1px 10px rgba(0,0,0,0.5);
		z-index: 0;
	}
	body:before {
		content: '';
		display: block;
		position: fixed;
		top: 3rem;
		left: 3rem;
		right: 3rem;
		bottom: 3rem;
		border-radius: 10px;
		border: 2px dashed #aaa;
		z-index: 1;
	}
	body > * {
		position: relative;
		z-index: 2;
	}
`;

export default GlobalStyles;