import styled, {createGlobalStyle} from "styled-components";
import {useEffect, useRef} from "react";

const BasicBlockLayout = ({children}) => {

	const wrapper = useRef()

	useEffect(() => {


		const html = document.querySelector('html');


		const wheel = function (event) {
			event.preventDefault();
			html.scroll({left: html.scrollLeft + event.deltaY})
		}

		html.addEventListener('wheel', wheel);

		return () => html.removeEventListener('wheel', wheel);
	}, []);

	return <>
		<BasicGlobalBlockLayout/>
		<BasicBlockLayoutWrapper ref={wrapper}>
			{children}
		</BasicBlockLayoutWrapper>
	</>
}

const BasicGlobalBlockLayout = createGlobalStyle`
	html {
		overflow-y: hidden;
	}

	body {
		writing-mode: vertical-lr;
	}

`;

const BasicBlockLayoutWrapper = styled.div`
	display: flex;
	flex-direction: column;
	align-items: center;

	& > * > * {;
		writing-mode: horizontal-tb;
	}
	
`;

export default BasicBlockLayout;